package qrspicmd

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

func TestResolveSessionPathMatchesExactIDInCustomSessionDir(t *testing.T) {
	root := t.TempDir()
	cwd := filepath.Join(root, "repo")
	want := writePiSession(t, root, "target.jsonl", "session-1", cwd)
	writePiSession(t, root, "other.jsonl", "session-2", cwd)

	got, err := ResolveSessionPath(root, "session-1", cwd)
	if err != nil {
		t.Fatalf("ResolveSessionPath error = %v", err)
	}
	if got != want {
		t.Fatalf("path = %q, want %q", got, want)
	}
}

func TestResolveSessionPathFindsPiCwdSubdirectory(t *testing.T) {
	root := t.TempDir()
	cwd := "/tmp/repo"
	want := writePiSession(
		t,
		filepath.Join(root, "--tmp-repo--"),
		"target.jsonl",
		"session-1",
		cwd,
	)

	got, err := ResolveSessionPath(root, "session-1", cwd)
	if err != nil {
		t.Fatalf("ResolveSessionPath error = %v", err)
	}
	if got != want {
		t.Fatalf("path = %q, want %q", got, want)
	}
}

func TestResolveSessionPathRejectsMissingOrDuplicate(t *testing.T) {
	root := t.TempDir()
	cwd := "/tmp/repo"
	if _, err := ResolveSessionPath(
		root,
		"missing",
		cwd,
	); err == nil ||
		!strings.Contains(err.Error(), "not found") {
		t.Fatalf("expected missing error, got %v", err)
	}
	writePiSession(t, root, "one.jsonl", "dup", cwd)
	writePiSession(t, root, "two.jsonl", "dup", cwd)
	if _, err := ResolveSessionPath(
		root,
		"dup",
		cwd,
	); err == nil ||
		!strings.Contains(err.Error(), "multiple") {
		t.Fatalf("expected duplicate error, got %v", err)
	}
}

func TestResolveSessionPathDoesNotAcceptSiblingCWD(t *testing.T) {
	root := t.TempDir()
	cwd := "/tmp/repo"
	writePiSession(t, root, "sibling.jsonl", "target", "/tmp/other")

	_, err := ResolveSessionPath(root, "target", cwd)
	if err == nil || !strings.Contains(err.Error(), "not found") {
		t.Fatalf("expected not found for wrong cwd, got %v", err)
	}
}

func TestExtractFinalAssistantTextFromSessionUsesLastAssistantResult(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, strings.Join([]string{
		sessionHeader("s", "/tmp/repo"),
		assistantLine("first qrspi_result"),
		`{"type":"message","message":{"role":"user","content":"qrspi_result user text"}}`,
		assistantLine("final qrspi_result"),
	}, "\n")+"\n")

	got, err := ExtractFinalAssistantTextFromSession(path)
	if err != nil {
		t.Fatalf("ExtractFinalAssistantTextFromSession error = %v", err)
	}
	if got != "final qrspi_result" {
		t.Fatalf("text = %q", got)
	}
}

func TestExtractFinalAssistantTextFromSessionIgnoresMalformedToolThinkingAndAborted(
	t *testing.T,
) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, strings.Join([]string{
		sessionHeader("s", "/tmp/repo"),
		`not-json`,
		`{"type":"message","message":{"role":"assistant","stopReason":"aborted","content":[{"type":"text","text":"aborted qrspi_result"}]}}`,
		`{"type":"message","message":{"role":"assistant","content":[{"type":"thinking","text":"qrspi_result hidden"},{"type":"tool_use","text":"qrspi_result tool"}]}}`,
		assistantLine("visible qrspi_result"),
	}, "\n")+"\n")

	got, err := ExtractFinalAssistantTextFromSession(path)
	if err != nil {
		t.Fatalf("ExtractFinalAssistantTextFromSession error = %v", err)
	}
	if got != "visible qrspi_result" {
		t.Fatalf("text = %q", got)
	}
}

func TestExtractFinalAssistantTextFromSessionErrorsWithoutQRSPIResult(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(
		t,
		path,
		sessionHeader("s", "/tmp/repo")+"\n"+assistantLine("plain text")+"\n",
	)

	_, err := ExtractFinalAssistantTextFromSession(path)
	if err == nil ||
		!strings.Contains(err.Error(), "no assistant text containing qrspi_result") {
		t.Fatalf("expected missing qrspi_result error, got %v", err)
	}
}

func TestLatestAssistantTerminalEvidenceDetectsProviderContextError(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(t, path, strings.Join([]string{
		sessionHeader("verify-1", "/tmp/repo"),
		assistantLine("older qrspi_result"),
		providerContextErrorLine(
			"Codex error: Your input exceeds the context window of this model. Please adjust your input and try again.",
		),
	}, "\n")+"\n")

	got, ok, err := LatestAssistantTerminalEvidence(path)
	if err != nil || !ok {
		t.Fatalf("LatestAssistantTerminalEvidence = %+v %v %v", got, ok, err)
	}
	if got.SessionID != "verify-1" || got.Line != 3 ||
		got.Timestamp != "2026-07-04T23:15:59.015Z" ||
		got.StopReason != "error" ||
		!got.ContextWindowError ||
		got.EvidenceID == "" {
		t.Fatalf("evidence = %+v", got)
	}

	again, ok, err := LatestAssistantTerminalEvidence(path)
	if err != nil || !ok {
		t.Fatalf("second LatestAssistantTerminalEvidence = %+v %v %v", again, ok, err)
	}
	if again.EvidenceID != got.EvidenceID {
		t.Fatalf("evidence ID changed: %q != %q", again.EvidenceID, got.EvidenceID)
	}
}

func TestLatestAssistantTerminalEvidenceKeepsExtractorStrict(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(
		t,
		path,
		sessionHeader(
			"s",
			"/tmp/repo",
		)+"\n"+providerContextErrorLine(
			"context window exceeded",
		)+"\n",
	)

	_, err := ExtractFinalAssistantTextFromSession(path)
	if err == nil ||
		!strings.Contains(err.Error(), "no assistant text containing qrspi_result") {
		t.Fatalf("expected no result error, got %v", err)
	}
}

func TestIsContextWindowErrorMessage(t *testing.T) {
	for _, message := range []string{
		"Codex error: Your input exceeds the context window of this model.",
		"context length exceeded",
		"context_length_exceeded",
		"maximum context tokens exceeded",
		"hit the context limit",
	} {
		if !IsContextWindowErrorMessage(message) {
			t.Fatalf("expected context-window match for %q", message)
		}
	}
	if IsContextWindowErrorMessage("network connection reset") {
		t.Fatal("unexpected context-window match")
	}
}

func TestTextBlocksFromAssistantMessageAcceptsStringContent(t *testing.T) {
	path := filepath.Join(t.TempDir(), "session.jsonl")
	writeSessionTestFile(
		t,
		path,
		sessionHeader(
			"s",
			"/tmp/repo",
		)+"\n"+`{"type":"message","message":{"role":"assistant","content":"string qrspi_result"}}`+"\n",
	)

	got, err := ExtractFinalAssistantTextFromSession(path)
	if err != nil {
		t.Fatalf("ExtractFinalAssistantTextFromSession error = %v", err)
	}
	if got != "string qrspi_result" {
		t.Fatalf("text = %q", got)
	}
}

func writePiSession(
	t *testing.T,
	sessionRoot, name, sessionID, cwd string,
	lines ...string,
) string {
	t.Helper()
	path := filepath.Join(sessionRoot, name)
	content := append([]string{sessionHeader(sessionID, cwd)}, lines...)
	writeSessionTestFile(t, path, strings.Join(content, "\n")+"\n")
	return path
}

func sessionHeader(sessionID, cwd string) string {
	return fmt.Sprintf(
		`{"type":"session","version":3,"id":%q,"timestamp":"2026-06-20T00:00:00Z","cwd":%q}`,
		sessionID,
		cwd,
	)
}

func assistantLine(text string) string {
	return fmt.Sprintf(
		`{"type":"message","message":{"role":"assistant","stopReason":"endTurn","content":[{"type":"thinking","text":"hidden"},{"type":"text","text":%q}]}}`,
		text,
	)
}

func providerContextErrorLine(message string) string {
	return fmt.Sprintf(
		`{"type":"message","timestamp":"2026-07-04T23:15:59.015Z","message":{"role":"assistant","content":[],"provider":"openai-codex","model":"gpt-5.5","stopReason":"error","errorMessage":%q}}`,
		message,
	)
}

func writeSessionTestFile(t *testing.T, path, content string) {
	t.Helper()
	if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
		t.Fatal(err)
	}
	if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
		t.Fatal(err)
	}
}

package qrspicmd

import (
	"bytes"
	"path/filepath"
	"strings"
	"testing"

	"github.com/CoreyCole/vamos/pkg/agents/workflows/qrspi"
)

func TestInspectActiveChildHealthRunning(t *testing.T) {
	state := ManagerState{
		ActiveChild: &ChildRunRef{ID: "child-1", Stage: "design", TmuxPaneID: "%9"},
	}
	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildRunning {
		t.Fatalf("status = %s, want %s", health.Status, ActiveChildRunning)
	}
}

func TestInspectActiveChildHealthFinishedSuccessNeedsValidation(t *testing.T) {
	dir := t.TempDir()
	active := childHealthRef(dir)
	writeFile(t, active.StatusPath, `{"exitCode":0}`)
	writeFile(t, active.DonePath, "")
	state := ManagerState{ActiveChild: active}
	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildFinishedNeedsValidation || health.ExitCode == nil ||
		*health.ExitCode != 0 {
		t.Fatalf("health = %+v, want success-needs-validation", health)
	}
}

func TestInspectActiveChildHealthLaunchFailed(t *testing.T) {
	dir := t.TempDir()
	active := childHealthRef(dir)
	writeFile(t, active.StatusPath, `{"exitCode":1}`)
	writeFile(t, active.DonePath, "")
	writeFile(
		t,
		active.OutputPath,
		"Error: unknown option --session-id\nUsage:\n  pi [flags]\nFlags:\n  --session string\n",
	)
	state := ManagerState{ActiveChild: active}
	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%9": true}}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildLaunchFailed || health.ExitCode == nil ||
		*health.ExitCode != 1 {
		t.Fatalf("health = %+v, want launch failed exit 1", health)
	}
	if !containsLine(health.OutputTail, "Error: unknown option --session-id") ||
		containsLine(health.OutputTail, "Usage:") {
		t.Fatalf("output tail = %#v", health.OutputTail)
	}
}

func TestInspectActiveChildHealthDoesNotMarkFailureWhenSessionHasResult(t *testing.T) {
	dir := t.TempDir()
	active := childHealthRef(dir)
	active.Cwd = dir
	active.SessionPath = filepath.Join(active.SessionDir, "session.jsonl")
	writeFile(t, active.StatusPath, `{"exitCode":1}`)
	writeFile(t, active.DonePath, "")
	writeSessionTestFile(
		t,
		active.SessionPath,
		sessionHeader(
			active.SessionID,
			active.Cwd,
		)+"\n"+assistantLine(
			testResultYAML(
				"design",
				"complete",
				"complete",
				"thoughts/example/design.md",
				"",
			),
		)+"\n",
	)
	state := ManagerState{ActiveChild: active}
	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%9": true}}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildFinishedNeedsValidation {
		t.Fatalf(
			"status = %s, want %s",
			health.Status,
			ActiveChildFinishedNeedsValidation,
		)
	}
}

func TestInspectActiveChildHealthPaneMissing(t *testing.T) {
	state := ManagerState{
		ActiveChild: &ChildRunRef{ID: "child-1", Stage: "design", TmuxPaneID: "%missing"},
	}
	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%missing": true}}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildPaneMissing {
		t.Fatalf("status = %s, want %s", health.Status, ActiveChildPaneMissing)
	}
}

func TestInspectActiveChildHealthProviderContextErrorOutranksOlderResult(t *testing.T) {
	dir := t.TempDir()
	active := childHealthRef(dir)
	active.Cwd = dir
	active.SessionPath = filepath.Join(active.SessionDir, "session.jsonl")
	writeFile(t, active.StatusPath, `{"exitCode":0}`)
	writeFile(t, active.DonePath, "")
	writeSessionWithBlockedResultThenProviderError(
		t,
		active.SessionPath,
		active.SessionID,
		active.Cwd,
	)
	state := ManagerState{ActiveChild: active}

	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%9": true}}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildProviderContextError ||
		health.TerminalEvidence == nil ||
		!health.TerminalEvidence.ContextWindowError {
		t.Fatalf("health = %+v, want provider context error", health)
	}
	if !containsLine(health.Evidence, "provider stopReason: error") ||
		!strings.Contains(
			strings.Join(health.Evidence, "\n"),
			"input exceeds the context window",
		) {
		t.Fatalf("evidence = %#v", health.Evidence)
	}
}

func TestInspectActiveChildHealthDetectsContextExhaustionNoResult(t *testing.T) {
	dir := t.TempDir()
	active := childHealthRef(dir)
	active.SessionPath = filepath.Join(active.SessionDir, "session.jsonl")
	writeFile(t, active.StatusPath, `{"exitCode":1}`)
	writeFile(t, active.DonePath, "")
	writeSessionTestFile(
		t,
		active.SessionPath,
		sessionHeader(
			active.SessionID,
			active.Cwd,
		)+"\n"+assistantLine(
			"provider error: context length exceeded before required fenced YAML emitted",
		)+"\n",
	)
	state := ManagerState{ActiveChild: active}

	health, err := InspectActiveChildHealth(
		t.Context(),
		state,
		"state.json",
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%9": true}}},
	)
	if err != nil {
		t.Fatal(err)
	}
	if health.Status != ActiveChildContextExhausted {
		t.Fatalf("health = %+v, want context exhausted", health)
	}
	if health.SessionPath != active.SessionPath ||
		!strings.Contains(health.SafeCommand, "pi --resume") {
		t.Fatalf("health session/safe command = %+v", health)
	}
}

func TestContinueProviderContextErrorWritesActionCardWithoutAdvance(t *testing.T) {
	dir := t.TempDir()
	stateFile := filepath.Join(dir, "state.json")
	active := childHealthRef(dir)
	active.Cwd = dir
	active.SessionPath = filepath.Join(active.SessionDir, "session.jsonl")
	writeFile(t, active.StatusPath, `{"exitCode":0}`)
	writeFile(t, active.DonePath, "")
	writeSessionWithBlockedResultThenProviderError(
		t,
		active.SessionPath,
		active.SessionID,
		active.Cwd,
	)
	state := ManagerState{
		CanonicalPlanDir: "thoughts/example",
		ActiveChild:      active,
		Workflow:         testWorkflowState(t, qrspi.NodeDesign, nil),
	}
	saveManagerState(t, stateFile, state)

	var out bytes.Buffer
	if err := RunContinue(
		t.Context(),
		ContinueOptions{
			StateFile: stateFile,
			PlanDir:   "thoughts/example",
			Output:    "text",
		},
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%9": true}}},
		&out,
	); err != nil {
		t.Fatal(err)
	}
	text := out.String()
	if !strings.Contains(text, "action: child_context_exhausted") ||
		!strings.Contains(text, "provider_context_error") ||
		!strings.Contains(text, "input exceeds the context window") ||
		!strings.Contains(text, "evidence id:") ||
		!strings.Contains(text, active.SessionPath) ||
		!strings.Contains(
			text,
			"safe command: vamos qrspi inspect --state-file "+stateFile+" --sessions --latest",
		) ||
		!strings.Contains(
			text,
			"continue: vamos qrspi recover-manual --state-file "+stateFile+" --mode latest-session --continue",
		) ||
		!strings.Contains(
			text,
			"recovery summary: vamos qrspi recover-summary --state-file "+stateFile+" --session-file "+active.SessionPath,
		) {
		t.Fatalf("output = %s", text)
	}
	loaded := loadManagerState(t, stateFile)
	if loaded.Workflow.CurrentNodeID != qrspi.NodeDesign ||
		loaded.LastActionCard == nil ||
		loaded.LastActionCard.Kind != ActionChildContextExhausted {
		t.Fatalf("loaded state = %+v", loaded)
	}
}

func TestRunInspectProviderContextErrorShowsEvidenceAndSafeCommand(t *testing.T) {
	dir := t.TempDir()
	stateFile := filepath.Join(dir, "state.json")
	active := childHealthRef(dir)
	active.Cwd = dir
	active.SessionPath = filepath.Join(active.SessionDir, "session.jsonl")
	writeFile(t, active.StatusPath, `{"exitCode":0}`)
	writeFile(t, active.DonePath, "")
	writeSessionWithBlockedResultThenProviderError(
		t,
		active.SessionPath,
		active.SessionID,
		active.Cwd,
	)
	state := ManagerState{
		CanonicalPlanDir: "thoughts/example",
		ActiveChild:      active,
		Workflow:         testWorkflowState(t, qrspi.NodeDesign, nil),
	}
	saveManagerState(t, stateFile, state)

	var out bytes.Buffer
	if err := RunInspect(
		t.Context(),
		InspectOptions{StateFile: stateFile, Sessions: true, Latest: true},
		deps{Tmux: &recordingTmux{missingPanes: map[string]bool{"%9": true}}},
		&out,
	); err != nil {
		t.Fatal(err)
	}
	text := out.String()
	if !strings.Contains(text, "active child health: provider_context_error") ||
		!strings.Contains(
			text,
			"provider error: Codex error: Your input exceeds the context window",
		) ||
		!strings.Contains(text, "evidence: evidence id:") ||
		!strings.Contains(text, active.SessionPath) ||
		!strings.Contains(
			text,
			"safe command: vamos qrspi inspect --state-file "+stateFile+" --sessions --latest",
		) {
		t.Fatalf("output = %s", text)
	}
}

