			testResultYAML(
				"design",
				"complete",
				"complete",
				"thoughts/example/design.md",
				"",
			),
		),
	)
	newPath := writePiSession(
		t,
		sessionDir,
		"new.jsonl",
		"session-new",
		cwd,
		assistantLine(
			testResultYAML(
				"design",
				"complete",
				"complete",
				"thoughts/example/design.md",
				"",
			),
		),
	)
	oldTime := time.Date(2026, 6, 21, 1, 0, 0, 0, time.UTC)
	newTime := oldTime.Add(time.Minute)
	chtimes(t, oldPath, oldTime)
	chtimes(t, newPath, newTime)

	candidate, ok, err := FindLatestRelevantChildSession(
		LatestChildQuery{
			Stage:        qrspi.NodeDesign,
			WorkspaceCwd: cwd,
			SessionDir:   sessionDir,
			ActiveChild: &ChildRunRef{
				ID:          "child-1",
